-- ── Fix remaining nulls via nearest_isacord ──────────────
UPDATE thread_library t
  SET hex_color=ref.hex_color, r=ref.r, g=ref.g, b=ref.b
  FROM thread_library ref
  WHERE t.nearest_isacord=ref.color_code
  AND ref.brand_key='isacord' AND ref.r IS NOT NULL AND t.r IS NULL;

-- ── Verify ───────────────────────────────────────────────
SELECT brand_key, COUNT(*) total,
  COUNT(*) FILTER (WHERE r IS NULL) missing_rgb
FROM thread_library
GROUP BY brand_key ORDER BY missing_rgb DESC LIMIT 20;
